const slug = $('Script Writing').item.json.book_slug;
const notesContent = $('Read Notes').item.json.content;
const storyboardContent = $('Read Storyboard').item.json.content;
const ttsConfig = $('Read TTS Config').item.json.content || '{ "chunk": { "min": 75, "target": 140, "max": 250 } }';
const styleGuide = $('Read Style Guide').item.json.content || '(style guide not available)';
let systemPrompt = $('Read Prompt').item.json.content;

if (!storyboardContent) {
  throw new Error('Storyboard not found for book: ' + slug + '. Run storyboard step first.');
}
if (!notesContent) {
  throw new Error('Notes not found for book: ' + slug + '. Run research step first.');
}
if (!systemPrompt) {
  throw new Error('Script prompt not found at n8n/prompts/script.md');
}

// Replace placeholders
systemPrompt = systemPrompt.replace(/\{\{book_slug\}\}/g, slug);
systemPrompt = systemPrompt.replace(/\{\{storyboard_content\}\}/g, storyboardContent);
systemPrompt = systemPrompt.replace(/\{\{notes_content\}\}/g, notesContent);
systemPrompt = systemPrompt.replace(/\{\{tts_config\}\}/g, ttsConfig);
systemPrompt = systemPrompt.replace(/\{\{style_guide\}\}/g, styleGuide);

const userMessage = 'Write the video script following the storyboard. Output both chunks-display (natural Vietnamese) and chunks (TTS-normalized) versions. Follow the output format with ---OUTPUT START--- / ---OUTPUT END--- delimiters and === CHUNKS-DISPLAY === / === CHUNKS-TTS === / === SUMMARY === separators.';

return [{ json: { systemPrompt, userMessage, slug } }];

const slug = $('Build Prompt').item.json.slug;
const responseText = $json.content[0].text;

// Extract content between delimiters if present
let output;
const startMarker = '---OUTPUT START---';
const endMarker = '---OUTPUT END---';
const startIdx = responseText.indexOf(startMarker);
const endIdx = responseText.indexOf(endMarker);

if (startIdx !== -1 && endIdx !== -1) {
  output = responseText.substring(startIdx + startMarker.length, endIdx).trim();
} else {
  output = responseText.trim();
}

// Split into chunks-display and chunks-tts sections
const displayMarker = '=== CHUNKS-DISPLAY ===';
const ttsMarker = '=== CHUNKS-TTS ===';
const summaryMarker = '=== SUMMARY ===';

let chunksDisplay = '';
let chunksTts = '';
let llmSummary = '';

const displayIdx = output.indexOf(displayMarker);
const ttsIdx = output.indexOf(ttsMarker);
const summaryIdx = output.indexOf(summaryMarker);

if (displayIdx !== -1 && ttsIdx !== -1) {
  chunksDisplay = output.substring(displayIdx + displayMarker.length, ttsIdx).trim();
  if (summaryIdx !== -1) {
    chunksTts = output.substring(ttsIdx + ttsMarker.length, summaryIdx).trim();
    llmSummary = output.substring(summaryIdx + summaryMarker.length).trim();
  } else {
    chunksTts = output.substring(ttsIdx + ttsMarker.length).trim();
  }
} else {
  // Fallback: save the entire output as both
  chunksDisplay = output;
  chunksTts = output;
}

// Count chunks from display version
const chunkMatches = chunksDisplay.match(/^\[\d{3}\]/gm);
const chunkCount = chunkMatches ? chunkMatches.length : 0;

return [{ json: { slug, chunksDisplay, chunksTts, llmSummary, chunkCount } }];

const data = $('Parse Response').item.json;
const ttsContent = data.chunksTts;

// Parse TTS config for sweet spot bounds
let min = 75;
let max = 250;
try {
  const configStr = $('Read TTS Config').item.json.content;
  if (configStr) {
    const config = JSON.parse(configStr);
    min = config.chunk?.min || 75;
    max = config.chunk?.max || 250;
  }
} catch (e) {}

// Extract chunk texts
const chunkRegex = /^\[(\d{3})\]\s*"(.+?)"$/gm;
let match;
const chunks = [];
while ((match = chunkRegex.exec(ttsContent)) !== null) {
  chunks.push({ num: match[1], text: match[2], len: match[2].length });
}

const tooShort = chunks.filter(c => c.len < 30);
const short = chunks.filter(c => c.len >= 30 && c.len < min);
const sweetSpot = chunks.filter(c => c.len >= min && c.len <= max);
const tooLong = chunks.filter(c => c.len > max);

const warnings = [];
if (tooShort.length > 0) {
  warnings.push(tooShort.length + ' chunk(s) < 30 chars (noise): ' + tooShort.map(c => '[' + c.num + '] ' + c.len + 'ch').join(', '));
}
if (short.length > 0) {
  warnings.push(short.length + ' chunk(s) 30-' + (min - 1) + ' chars (short): ' + short.map(c => '[' + c.num + '] ' + c.len + 'ch').join(', '));
}
if (tooLong.length > 0) {
  warnings.push(tooLong.length + ' chunk(s) > ' + max + ' chars (long): ' + tooLong.map(c => '[' + c.num + '] ' + c.len + 'ch').join(', '));
}

return [{
  json: {
    slug: data.slug,
    chunkCount: data.chunkCount,
    displayLength: data.chunksDisplay.length,
    ttsLength: data.chunksTts.length,
    llmSummary: data.llmSummary,
    validation: {
      totalChunks: chunks.length,
      sweetSpot: sweetSpot.length,
      short: short.length,
      tooShort: tooShort.length,
      tooLong: tooLong.length,
      warnings
    }
  }
}];

const data = $json;
const v = data.validation;

const lines = [
  'Script written for: ' + data.slug,
  '',
  'Files:',
  '  Display: books/' + data.slug + '/chunks-display.md (' + data.displayLength + ' chars)',
  '  TTS: books/' + data.slug + '/chunks.md (' + data.ttsLength + ' chars)',
  '',
  'Chunks: ' + data.chunkCount + ' total',
];

if (typeof v === 'object' && v !== null) {
  lines.push('');
  lines.push('Validation:');
  lines.push('  In sweet spot (75-250 chars): ' + v.sweetSpot);
  lines.push('  Short (30-74 chars): ' + v.short);
  lines.push('  Too short (<30 chars): ' + v.tooShort);
  lines.push('  Too long (>250 chars): ' + v.tooLong);

  if (v.warnings && v.warnings.length > 0) {
    lines.push('');
    lines.push('Warnings:');
    for (const w of v.warnings) {
      lines.push('  - ' + w);
    }
  }
}

if (data.llmSummary) {
  lines.push('');
  lines.push('LLM Summary:');
  lines.push(data.llmSummary);
}

lines.push('');
lines.push('Next step: Run 05-Voice workflow to generate audio.');

return [{ json: { summary: lines.join('\n') } }];
